class Solution {
public:
    vector<int> maxScoreIndices(vector<int>& nums) {
        int n = nums.size();
        int totalOnes = 0;
        for (int num : nums) totalOnes += num;

        int maxScore = 0;
        vector<int> res;

        int leftZeros = 0;
        int rightOnes = totalOnes;

        for (int i = 0; i <= n; ++i) {
            int score = leftZeros + rightOnes;
            if (score > maxScore) {
                maxScore = score;
                res.clear();
                res.push_back(i);
            } else if (score == maxScore) {
                res.push_back(i);
            }

            if (i < n) {
                if (nums[i] == 0) {
                    leftZeros++;
                } else {
                    rightOnes--;
                }
            }
        }

        return res;
    }
};
